                 .WithMany(t => t.CourseAssignments)
                 .HasForeignKey(m => m.CourseID);

             modelBuilder.Entity<CourseAssignment>()
                 .HasOne(m => m.Instructor)
                 .WithMany(t => t.CourseAssignments)
                 .HasForeignKey(m => m.InstructorID);

             // Configure one-to-one relationship
