        [DataRow("John", "Doe", "Doe, John", DisplayName = "Standard name")]
        [DataRow("Mary Jane", "Watson-Parker", "Watson-Parker, Mary Jane", DisplayName = "Hyphenated and multi-word")]
        [DataRow("A", "B", "B, A", DisplayName = "Single character names")]
        public void Person_FullName_FormatsCorrectly(string firstName, string lastName, string expected)
        {
