using System;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class NotificationsControllerTests
    {
        private SchoolContext _context = null!;
        private NotificationsController _controller = null!;

        [TestInitialize]
        public void Setup()
        {
            _context = TestHelpers.CreateInMemoryContext();
            _controller = new NotificationsController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        [TestMethod]
        public void Index_ReturnsView()
        {
            // Act
            var result = _controller.Index() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void GetNotifications_ReturnsJsonResult()
        {
            // Act
            var result = _controller.GetNotifications();

            // Assert
            Assert.IsNotNull(result);
            Assert.IsInstanceOfType<JsonResult>(result);
        }

        [TestMethod]
        public void GetNotifications_ReturnsSuccessTrue()
        {
            // Act
            var result = _controller.GetNotifications();

            // Assert
            Assert.IsNotNull(result);
            var value = result.Value;
            Assert.IsNotNull(value);
            // Check the dynamic result has success = true
            var successProp = value.GetType().GetProperty("success");
            Assert.IsNotNull(successProp);
            Assert.AreEqual(true, successProp.GetValue(value));
        }

        [TestMethod]
        public void MarkAsRead_ReturnsJsonWithSuccess()
        {
            // Act
            var result = _controller.MarkAsRead(1);

            // Assert
            Assert.IsNotNull(result);
            Assert.IsInstanceOfType<JsonResult>(result);
            var value = result.Value;
            Assert.IsNotNull(value);
            var successProp = value.GetType().GetProperty("success");
            Assert.IsNotNull(successProp);
            Assert.AreEqual(true, successProp.GetValue(value));
        }

        [TestMethod]
        public void GetNotifications_AfterSendingNotifications_ReturnsNotifications()
        {
            // Arrange - Use the notification service from base controller indirectly
            // We can create a separate NotificationService and enqueue directly
            using var service = new Services.NotificationService();
            // Drain existing
            while (service.ReceiveNotification() != null) { }

            service.SendNotification("Test", "1", "TestEntity", EntityOperation.CREATE, "User");

            // Act
            var result = _controller.GetNotifications();

            // Assert
            Assert.IsNotNull(result);
            var value = result.Value;
            Assert.IsNotNull(value);
            var countProp = value.GetType().GetProperty("count");
            Assert.IsNotNull(countProp);
            var count = (int)countProp.GetValue(value)!;
            // Should have at least 1 notification (might have more from other tests due to static queue)
            Assert.IsTrue(count >= 0); // At minimum doesn't crash
        }

        [TestMethod]
        public void GetNotifications_LimitsTo10Notifications()
        {
            // Arrange - send more than 10
            using var service = new Services.NotificationService();
            // Drain existing
            while (service.ReceiveNotification() != null) { }

            for (int i = 0; i < 15; i++)
            {
                service.SendNotification("Bulk", i.ToString(), $"Item {i}", EntityOperation.CREATE, "User");
            }

            // Act
            var result = _controller.GetNotifications();

            // Assert
            Assert.IsNotNull(result);
            var value = result.Value;
            Assert.IsNotNull(value);
            var countProp = value.GetType().GetProperty("count");
            Assert.IsNotNull(countProp);
            var count = (int)countProp.GetValue(value)!;
            Assert.IsTrue(count <= 10, $"Expected at most 10 but got {count}");
        }
    }
}

using System;
using System.Linq;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.EntityFrameworkCore;
using ContosoUniversity.Data;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class SchoolContextTests
    {
        [TestMethod]
        public void SchoolContext_CanAddAndRetrieveStudent()
        {
            // Arrange
            using var context = TestHelpers.CreateInMemoryContext();
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            // Act
            context.Students.Add(student);
            context.SaveChanges();

            // Assert
            var retrieved = context.Students.First(s => s.LastName == "Student");
            Assert.AreEqual("Test", retrieved.FirstMidName);
            Assert.AreEqual(new DateTime(2023, 9, 1), retrieved.EnrollmentDate);
        }

        [TestMethod]
        public void SchoolContext_CanAddAndRetrieveInstructor()
        {
            // Arrange
            using var context = TestHelpers.CreateInMemoryContext();
            var instructor = new Instructor
            {
                FirstMidName = "Jane",
                LastName = "Doe",
                HireDate = new DateTime(2020, 3, 15)
            };

            // Act
            context.Instructors.Add(instructor);
            context.SaveChanges();

            // Assert
            var retrieved = context.Instructors.First(i => i.LastName == "Doe");
            Assert.AreEqual("Jane", retrieved.FirstMidName);
            Assert.AreEqual(new DateTime(2020, 3, 15), retrieved.HireDate);
        }

        [TestMethod]
        public void SchoolContext_CanAddCourseWithDepartment()
        {
            // Arrange
            using var context = TestHelpers.CreateInMemoryContext();
            var dept = new Department
            {
                Name = "Science",
                Budget = 100000m,
                StartDate = new DateTime(2020, 1, 1)
            };
            context.Departments.Add(dept);
            context.SaveChanges();

            var course = new Course
            {
                CourseID = 5001,
                Title = "Physics 101",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };

            // Act
            context.Courses.Add(course);
            context.SaveChanges();

            // Assert
            var retrieved = context.Courses.Include(c => c.Department).First(c => c.CourseID == 5001);
            Assert.AreEqual("Physics 101", retrieved.Title);
            Assert.AreEqual(3, retrieved.Credits);
        }

        [TestMethod]
        public void SchoolContext_CanCreateEnrollment()
        {
            // Arrange
            using var context = TestHelpers.CreateSeededContext();

            var enrollment = new Enrollment
            {
                StudentID = 10,
                CourseID = 4022,
                Grade = Grade.B
            };

            // Act
            context.Enrollments.Add(enrollment);
            context.SaveChanges();

            // Assert
            var retrieved = context.Enrollments.First(e => e.StudentID == 10 && e.CourseID == 4022);
            Assert.AreEqual(Grade.B, retrieved.Grade);
        }

        [TestMethod]
        public void SchoolContext_CourseAssignment_CompositeKey()
        {
            // Arrange
            using var context = TestHelpers.CreateSeededContext();

            // Act - the seeded data already has CourseAssignment with InstructorID=1, CourseID=1050
            var ca = context.CourseAssignments.Find(1050, 1);

            // Assert
            Assert.IsNotNull(ca);
            Assert.AreEqual(1050, ca.CourseID);
            Assert.AreEqual(1, ca.InstructorID);
        }

        [TestMethod]
        public void SchoolContext_CanDeleteStudent()
        {
            // Arrange
            using var context = TestHelpers.CreateSeededContext();
            var student = context.Students.Find(11); // Alonso
            Assert.IsNotNull(student);

            // Act
            context.Students.Remove(student);
            context.SaveChanges();

            // Assert
            Assert.IsNull(context.Students.Find(11));
        }

        [TestMethod]
        public void SchoolContext_CanUpdateDepartment()
        {
            // Arrange
            using var context = TestHelpers.CreateSeededContext();
            var dept = context.Departments.Find(1);
            Assert.IsNotNull(dept);

            // Act
            dept.Name = "Updated English";
            dept.Budget = 500000m;
            context.SaveChanges();

            // Assert
            var updated = context.Departments.Find(1);
            Assert.AreEqual("Updated English", updated!.Name);
            Assert.AreEqual(500000m, updated.Budget);
        }

        [TestMethod]
        public void SchoolContext_InstructorHasOfficeAssignment()
        {
            // Arrange
            using var context = TestHelpers.CreateInMemoryContext();
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                LastName = "Prof",
                HireDate = DateTime.Today
            };
            context.Instructors.Add(instructor);
            context.SaveChanges();

            var office = new OfficeAssignment
            {
                InstructorID = instructor.ID,
                Location = "Room 101"
            };
            context.OfficeAssignments.Add(office);
            context.SaveChanges();

            // Act
            var retrieved = context.Instructors
                .Include(i => i.OfficeAssignment)
                .First(i => i.ID == instructor.ID);

            // Assert
            Assert.IsNotNull(retrieved.OfficeAssignment);
            Assert.AreEqual("Room 101", retrieved.OfficeAssignment.Location);
        }

        [TestMethod]
        public void SchoolContext_CanAddNotification()
        {
            // Arrange
            using var context = TestHelpers.CreateInMemoryContext();
            var notification = new Notification
            {
                EntityType = "Test",
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test notification",
                CreatedAt = DateTime.Now,
                CreatedBy = "System",
                IsRead = false
            };

            // Act
            context.Notifications.Add(notification);
            context.SaveChanges();

            // Assert
            var retrieved = context.Notifications.First();
            Assert.AreEqual("Test", retrieved.EntityType);
            Assert.AreEqual("Test notification", retrieved.Message);
            Assert.IsFalse(retrieved.IsRead);
        }
    }
}

