using Microsoft.EntityFrameworkCore;
using ContosoUniversity.Data;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests;

public static class TestHelpers
{
    public static SchoolContext CreateInMemoryContext(string? databaseName = null)
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName ?? Guid.NewGuid().ToString())
            .Options;

        var context = new SchoolContext(options);
        return context;
    }

    public static SchoolContext CreateSeededContext(string? databaseName = null)
    {
        var context = CreateInMemoryContext(databaseName);
        SeedDatabase(context);
        return context;
    }

    public static void SeedDatabase(SchoolContext context)
    {
        var instructor1 = new Instructor
        {
            ID = 1,
            FirstMidName = "Kim",
            LastName = "Abercrombie",
            HireDate = DateTime.Parse("1995-03-11"),
            CourseAssignments = new List<CourseAssignment>()
        };
        var instructor2 = new Instructor
        {
            ID = 2,
            FirstMidName = "Fadi",
            LastName = "Fakhouri",
            HireDate = DateTime.Parse("2002-07-06"),
            CourseAssignments = new List<CourseAssignment>()
        };

        context.Instructors.AddRange(instructor1, instructor2);

        var department1 = new Department
        {
            DepartmentID = 1,
            Name = "English",
            Budget = 350000,
            StartDate = DateTime.Parse("2007-09-01"),
            InstructorID = 1
        };
        var department2 = new Department
        {
            DepartmentID = 2,
            Name = "Mathematics",
            Budget = 100000,
            StartDate = DateTime.Parse("2007-09-01"),
            InstructorID = 2
        };

        context.Departments.AddRange(department1, department2);

        var course1 = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = 3,
            DepartmentID = 1,
            Enrollments = new List<Enrollment>()
        };
        var course2 = new Course
        {
            CourseID = 4022,
            Title = "Microeconomics",
            Credits = 3,
            DepartmentID = 2,
            Enrollments = new List<Enrollment>()
        };

        context.Courses.AddRange(course1, course2);

        var student1 = new Student
        {
            ID = 10,
            FirstMidName = "Carson",
            LastName = "Alexander",
            EnrollmentDate = DateTime.Parse("2010-09-01")
        };
        var student2 = new Student
        {
            ID = 11,
            FirstMidName = "Meredith",
            LastName = "Alonso",
            EnrollmentDate = DateTime.Parse("2012-09-01")
        };
        var student3 = new Student
        {
            ID = 12,
            FirstMidName = "Arturo",
            LastName = "Anand",
            EnrollmentDate = DateTime.Parse("2013-09-01")
        };

        context.Students.AddRange(student1, student2, student3);

        context.SaveChanges();

        context.Enrollments.Add(new Enrollment
        {
            EnrollmentID = 1,
            StudentID = 10,
            CourseID = 1050,
            Grade = Grade.A
        });

        context.CourseAssignments.Add(new CourseAssignment
        {
            InstructorID = 1,
            CourseID = 1050
        });

        context.SaveChanges();
    }
}

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    public void Constructor_ValidInputs_SetsPageIndex()
    {
        var items = new List<string> { "a", "b", "c" };
        var result = new PaginatedList<string>(items, 10, 2, 3);
        Assert.AreEqual(2, result.PageIndex);
    }

    [TestMethod]
    public void Constructor_ValidInputs_CalculatesTotalPages()
    {
        var items = new List<string> { "a", "b", "c" };
        var result = new PaginatedList<string>(items, 10, 1, 3);
        Assert.AreEqual(4, result.TotalPages); // ceil(10/3) = 4
    }

    [TestMethod]
    [DataRow(7, 3, 3, DisplayName = "7 items, page size 3 => 3 pages")]
    [DataRow(9, 3, 3, DisplayName = "9 items, page size 3 => 3 pages")]
    [DataRow(10, 3, 4, DisplayName = "10 items, page size 3 => 4 pages")]
    [DataRow(1, 10, 1, DisplayName = "1 item, page size 10 => 1 page")]
    [DataRow(0, 5, 0, DisplayName = "0 items, page size 5 => 0 pages")]
    public void Constructor_VariousCounts_CalculatesCorrectTotalPages(int count, int pageSize, int expectedTotalPages)
    {
        var items = new List<int>();
        var result = new PaginatedList<int>(items, count, 1, pageSize);
        Assert.AreEqual(expectedTotalPages, result.TotalPages);
    }

    [TestMethod]
    public void Constructor_AddsItemsToList()
    {
        var items = new List<string> { "alpha", "beta", "gamma" };
        var result = new PaginatedList<string>(items, 20, 1, 5);
        Assert.AreEqual(3, result.Count);
        Assert.AreEqual("alpha", result[0]);
        Assert.AreEqual("beta", result[1]);
        Assert.AreEqual("gamma", result[2]);
    }

    [TestMethod]
    public void HasPreviousPage_PageIndexIs1_ReturnsFalse()
    {
        var result = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 5);
        Assert.IsFalse(result.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_PageIndexGreaterThan1_ReturnsTrue()
    {
        var result = new PaginatedList<int>(new List<int> { 1 }, 10, 2, 5);
        Assert.IsTrue(result.HasPreviousPage);
    }

    [TestMethod]
    public void HasNextPage_OnLastPage_ReturnsFalse()
    {
        var result = new PaginatedList<int>(new List<int> { 1 }, 10, 2, 5); // TotalPages = 2
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_NotOnLastPage_ReturnsTrue()
    {
        var result = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 5); // TotalPages = 2
        Assert.IsTrue(result.HasNextPage);
    }

    [TestMethod]
    public void Create_FirstPage_ReturnsCorrectItems()
    {
        var source = Enumerable.Range(1, 20).AsQueryable();
        var result = PaginatedList<int>.Create(source, 1, 5);
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(1, result[0]);
        Assert.AreEqual(5, result[4]);
        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(4, result.TotalPages);
    }

    [TestMethod]
    public void Create_SecondPage_SkipsFirstPageItems()
    {
        var source = Enumerable.Range(1, 20).AsQueryable();
        var result = PaginatedList<int>.Create(source, 2, 5);
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(6, result[0]);
        Assert.AreEqual(10, result[4]);
    }

    [TestMethod]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        var source = Enumerable.Range(1, 12).AsQueryable();
        var result = PaginatedList<int>.Create(source, 3, 5);
        Assert.AreEqual(2, result.Count);
        Assert.AreEqual(11, result[0]);
        Assert.AreEqual(12, result[1]);
    }

    [TestMethod]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        var source = Enumerable.Empty<int>().AsQueryable();
        var result = PaginatedList<int>.Create(source, 1, 10);
        Assert.AreEqual(0, result.Count);
        Assert.AreEqual(0, result.TotalPages);
    }

    [TestMethod]
    public void Create_PageSizeEqualsCount_SinglePage()
    {
        var source = Enumerable.Range(1, 5).AsQueryable();
        var result = PaginatedList<int>.Create(source, 1, 5);
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(1, result.TotalPages);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }
}

using ContosoUniversity.Services;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class NotificationServiceTests
{
    [TestMethod]
    public void SendNotification_WithDisplayName_EnqueuesNotification()
    {
        using var sut = new NotificationService();
        // Drain any existing from the static queue
        while (sut.ReceiveNotification() != null) { }

        sut.SendNotification("Course", "101", "Chemistry", EntityOperation.CREATE, "TestUser");
        var result = sut.ReceiveNotification();

        Assert.IsNotNull(result);
        Assert.AreEqual("Course", result.EntityType);
        Assert.AreEqual("101", result.EntityId);
        Assert.AreEqual("CREATE", result.Operation);
        Assert.AreEqual("TestUser", result.CreatedBy);
        Assert.IsFalse(result.IsRead);
        Assert.IsTrue(result.Message.Contains("Chemistry"));
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        using var sut = new NotificationService();
        while (sut.ReceiveNotification() != null) { }

        sut.SendNotification("Student", "42", EntityOperation.UPDATE, "Admin");
        var result = sut.ReceiveNotification();

        Assert.IsNotNull(result);
        Assert.IsTrue(result.Message.Contains("ID: 42"));
    }

    [TestMethod]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        using var sut = new NotificationService();
        while (sut.ReceiveNotification() != null) { }

        sut.SendNotification("Course", "1", "Calculus", EntityOperation.CREATE);
        var result = sut.ReceiveNotification();

        Assert.IsNotNull(result);
        Assert.AreEqual("System", result.CreatedBy);
    }

    [TestMethod]
    [DataRow(EntityOperation.CREATE, "has been created", DisplayName = "CREATE generates created message")]
    [DataRow(EntityOperation.UPDATE, "has been updated", DisplayName = "UPDATE generates updated message")]
    [DataRow(EntityOperation.DELETE, "has been deleted", DisplayName = "DELETE generates deleted message")]
    public void SendNotification_DifferentOperations_GeneratesCorrectMessage(EntityOperation operation, string expectedPhrase)
    {
        using var sut = new NotificationService();
        while (sut.ReceiveNotification() != null) { }

        sut.SendNotification("Instructor", "5", "Dr. Smith", operation, "User1");
        var result = sut.ReceiveNotification();

        Assert.IsNotNull(result);
        Assert.IsTrue(result.Message.Contains(expectedPhrase),
            $"Expected message to contain '{expectedPhrase}' but was '{result.Message}'");
    }

    [TestMethod]
    public void SendNotification_CreateOperation_GeneratesCorrectMessage()
    {
        using var sut = new NotificationService();
        while (sut.ReceiveNotification() != null) { }

        sut.SendNotification("Department", "3", "Physics", EntityOperation.CREATE, "User");
        var result = sut.ReceiveNotification();

        Assert.IsNotNull(result);
        Assert.AreEqual("New Department 'Physics' has been created", result.Message);
    }

    [TestMethod]
    public void SendNotification_UpdateOperation_GeneratesCorrectMessage()
    {
        using var sut = new NotificationService();
        while (sut.ReceiveNotification() != null) { }

        sut.SendNotification("Student", "7", "John Doe", EntityOperation.UPDATE, "User");
        var result = sut.ReceiveNotification();

        Assert.IsNotNull(result);
        Assert.AreEqual("Student 'John Doe' has been updated", result.Message);
    }

    [TestMethod]
    public void SendNotification_DeleteOperation_GeneratesCorrectMessage()
    {
        using var sut = new NotificationService();
        while (sut.ReceiveNotification() != null) { }

        sut.SendNotification("Course", "99", "Biology", EntityOperation.DELETE, "User");
        var result = sut.ReceiveNotification();

        Assert.IsNotNull(result);
        Assert.AreEqual("Course 'Biology' has been deleted", result.Message);
    }

    [TestMethod]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        using var sut = new NotificationService();
        // Drain everything
        while (sut.ReceiveNotification() != null) { }

        var result = sut.ReceiveNotification();
        Assert.IsNull(result);
    }

    [TestMethod]
    public void SendNotification_MultipleMessages_DequeuesInOrder()
    {
        using var sut = new NotificationService();
        while (sut.ReceiveNotification() != null) { }

        sut.SendNotification("A", "1", "First", EntityOperation.CREATE, "User");
        sut.SendNotification("B", "2", "Second", EntityOperation.UPDATE, "User");
        sut.SendNotification("C", "3", "Third", EntityOperation.DELETE, "User");

        var first = sut.ReceiveNotification();
        var second = sut.ReceiveNotification();
        var third = sut.ReceiveNotification();

        Assert.IsNotNull(first);
        Assert.AreEqual("A", first.EntityType);
        Assert.IsNotNull(second);
        Assert.AreEqual("B", second.EntityType);
        Assert.IsNotNull(third);
        Assert.AreEqual("C", third.EntityType);
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAtToCurrentTime()
    {
        using var sut = new NotificationService();
        while (sut.ReceiveNotification() != null) { }
        var before = DateTime.Now;

        sut.SendNotification("Test", "1", "Item", EntityOperation.CREATE, "User");
        var after = DateTime.Now;
        var result = sut.ReceiveNotification();

        Assert.IsNotNull(result);
        Assert.IsTrue(result.CreatedAt >= before && result.CreatedAt <= after);
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        using var sut = new NotificationService();
        sut.MarkAsRead(1);
        sut.MarkAsRead(999);
    }

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        var sut = new NotificationService();
        sut.Dispose();
        sut.Dispose(); // Safe to call multiple times
    }

    [TestMethod]
    public void SendNotification_NullEntityDisplayName_UsesIdFormat()
    {
        using var sut = new NotificationService();
        while (sut.ReceiveNotification() != null) { }

        sut.SendNotification("Course", "55", null, EntityOperation.UPDATE, "User");
        var result = sut.ReceiveNotification();

        Assert.IsNotNull(result);
        Assert.IsTrue(result.Message.Contains("ID: 55"));
    }

    [TestMethod]
    public void SendNotification_EmptyDisplayName_UsesIdFormat()
    {
        using var sut = new NotificationService();
        while (sut.ReceiveNotification() != null) { }

        sut.SendNotification("Course", "55", "", EntityOperation.UPDATE, "User");
        var result = sut.ReceiveNotification();

        Assert.IsNotNull(result);
        Assert.IsTrue(result.Message.Contains("ID: 55"));
    }

    [TestMethod]
    public void SendNotification_WhitespaceDisplayName_UsesIdFormat()
    {
        using var sut = new NotificationService();
        while (sut.ReceiveNotification() != null) { }

        sut.SendNotification("Course", "55", "   ", EntityOperation.UPDATE, "User");
        var result = sut.ReceiveNotification();

        Assert.IsNotNull(result);
        Assert.IsTrue(result.Message.Contains("ID: 55"));
    }
}

