+{
+    [TestMethod]
+    public void SendNotification_WithDisplayName_EnqueuesNotification()
+    {
+        using var sut = new NotificationService();
+        // Drain any existing from the static queue
+        while (sut.ReceiveNotification() != null) { }
+
+        sut.SendNotification("Course", "101", "Chemistry", EntityOperation.CREATE, "TestUser");
+        var result = sut.ReceiveNotification();
+
+        Assert.IsNotNull(result);
+        Assert.AreEqual("Course", result.EntityType);
+        Assert.AreEqual("101", result.EntityId);
+        Assert.AreEqual("CREATE", result.Operation);
+        Assert.AreEqual("TestUser", result.CreatedBy);
+        Assert.IsFalse(result.IsRead);
+        Assert.IsTrue(result.Message.Contains("Chemistry"));
+    }
+
+    [TestMethod]
+    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
+    {
+        using var sut = new NotificationService();
+        while (sut.ReceiveNotification() != null) { }
+
+        sut.SendNotification("Student", "42", EntityOperation.UPDATE, "Admin");
