using ContosoUniversity.Data;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class StudentsControllerTests
{
    private SchoolContext _context = null!;
    private StudentsController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateSeededContext();
        _controller = new StudentsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    #region Index Tests

    [TestMethod]
    public void Index_NoParams_ReturnsViewWithStudents()
    {
        var result = _controller.Index(null, null, null, null) as ViewResult;
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(3, model.Count);
    }

    [TestMethod]
    public void Index_SortByNameDesc_ReturnsDescendingOrder()
    {
        var result = _controller.Index("name_desc", null, null, null) as ViewResult;
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Anand", model[0].LastName);
        Assert.AreEqual("Alonso", model[1].LastName);
        Assert.AreEqual("Alexander", model[2].LastName);
    }

    [TestMethod]
    public void Index_SortByDateAsc_ReturnsCorrectOrder()
    {
        var result = _controller.Index("Date", null, null, null) as ViewResult;
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Alexander", model[0].LastName); // 2010
        Assert.AreEqual("Alonso", model[1].LastName); // 2012
        Assert.AreEqual("Anand", model[2].LastName); // 2013
    }

    [TestMethod]
    public void Index_SortByDateDesc_ReturnsDescendingDateOrder()
    {
        var result = _controller.Index("date_desc", null, null, null) as ViewResult;
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Anand", model[0].LastName); // 2013
        Assert.AreEqual("Alonso", model[1].LastName); // 2012
        Assert.AreEqual("Alexander", model[2].LastName); // 2010
    }

    [TestMethod]
    public void Index_DefaultSort_OrdersByLastNameAsc()
    {
        var result = _controller.Index(null, null, null, null) as ViewResult;
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Alexander", model[0].LastName);
        Assert.AreEqual("Alonso", model[1].LastName);
        Assert.AreEqual("Anand", model[2].LastName);
    }

    [TestMethod]
    public void Index_SearchByLastName_FiltersResults()
    {
        var result = _controller.Index(null, null, "Alexander", null) as ViewResult;
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Alexander", model[0].LastName);
    }

    [TestMethod]
    public void Index_SearchByFirstName_FiltersResults()
    {
        var result = _controller.Index(null, null, "Meredith", null) as ViewResult;
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Alonso", model[0].LastName);
    }

    [TestMethod]
    public void Index_SearchStringProvided_ResetsPageTo1()
    {
        var result = _controller.Index(null, null, "A", 3) as ViewResult;
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.PageIndex);
    }

    [TestMethod]
    public void Index_CurrentFilterUsed_WhenSearchStringIsNull()
    {
        var result = _controller.Index(null, "Alexander", null, null) as ViewResult;
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
    }

    #endregion

    #region Details Tests

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);
        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithStudent()
    {
        var result = _controller.Details(10) as ViewResult;
        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual("Alexander", model.LastName);
        Assert.AreEqual("Carson", model.FirstMidName);
    }

    #endregion

    #region Create Tests

    [TestMethod]
    public void Create_Get_ReturnsViewWithDefaultDate()
    {
        var result = _controller.Create() as ViewResult;
        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(DateTime.Today, model.EnrollmentDate);
    }

    [TestMethod]
    public void Create_Post_ValidStudent_RedirectsToIndex()
    {
        var student = new Student
        {
            FirstMidName = "New",
            LastName = "Student",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };

        var result = _controller.Create(student) as RedirectToActionResult;
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);

        var saved = _context.Students.FirstOrDefault(s => s.LastName == "Student");
        Assert.IsNotNull(saved);
        Assert.AreEqual("New", saved.FirstMidName);
    }

    [TestMethod]
    public void Create_Post_MinValueDate_ReturnsView()
    {
        var student = new Student
        {
            FirstMidName = "Bad",
            LastName = "Date",
            EnrollmentDate = DateTime.MinValue
        };

        var result = _controller.Create(student) as ViewResult;
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("LastName", "Required");
        var student = new Student { FirstMidName = "Test", EnrollmentDate = DateTime.Today };

        var result = _controller.Create(student) as ViewResult;
        Assert.IsNotNull(result);
        Assert.AreEqual(student, result.Model);
    }

    #endregion

    #region Edit Tests

    [TestMethod]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit((int?)null);
        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Edit_Get_NotFound_ReturnsNotFound()
    {
        var result = _controller.Edit(9999);
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Edit_Get_ValidId_ReturnsViewWithStudent()
    {
        var result = _controller.Edit(10) as ViewResult;
        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual("Alexander", model.LastName);
    }

    [TestMethod]
    public void Edit_Post_ValidStudent_RedirectsToIndex()
    {
        var student = new Student
        {
            ID = 10,
            FirstMidName = "Carson Updated",
            LastName = "Alexander",
            EnrollmentDate = new DateTime(2010, 9, 1)
        };
        var existing = _context.Students.Find(10);
        if (existing != null) _context.Entry(existing).State = EntityState.Detached;

        var result = _controller.Edit(student) as RedirectToActionResult;
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
    }

    [TestMethod]
    public void Edit_Post_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("LastName", "Required");
        var student = new Student
        {
            ID = 10,
            FirstMidName = "Carson",
            LastName = "Alexander",
            EnrollmentDate = new DateTime(2010, 9, 1)
        };

        var result = _controller.Edit(student) as ViewResult;
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Edit_Post_MinValueDate_ReturnsView()
    {
        var student = new Student
        {
            ID = 10,
            FirstMidName = "Carson",
            LastName = "Alexander",
            EnrollmentDate = DateTime.MinValue
        };

        var result = _controller.Edit(student) as ViewResult;
        Assert.IsNotNull(result);
    }

    #endregion

    #region Delete Tests

    [TestMethod]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);
        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Delete_Get_NotFound_ReturnsNotFound()
    {
        var result = _controller.Delete(9999);
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Delete_Get_ValidId_ReturnsViewWithStudent()
    {
        var result = _controller.Delete(10) as ViewResult;
        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual("Alexander", model.LastName);
    }

    [TestMethod]
    public void DeleteConfirmed_ValidId_RemovesStudentAndRedirects()
    {
        var result = _controller.DeleteConfirmed(10) as RedirectToActionResult;
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.IsNull(_context.Students.Find(10));
    }

    #endregion
}

